// frontend/src/components/Navbar.js
import React, { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import API from "../api/axios";
import "../style.css";

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  // === HomePage state/effects ===
  const [darkMode, setDarkMode] = useState(false);
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get("/posts")
      .then((res) => setPosts(res.data))
      .finally(() => setLoading(false));
  }, []);

  const toggleTheme = () => setDarkMode(!darkMode);

  useEffect(() => {
    const savedTheme = localStorage.getItem("theme");
    if (savedTheme === "dark") setDarkMode(true);
  }, []);

  useEffect(() => {
    if (darkMode) {
      document.body.classList.add("dark-mode");
      localStorage.setItem("theme", "dark");
    } else {
      document.body.classList.remove("dark-mode");
      localStorage.setItem("theme", "light");
    }
  }, [darkMode]);

  const handleLogout = () => {
    logout();
    navigate("/");
  };

  if (loading) return <p>Loading posts...</p>;

  return (
    <div>
      {/* === Navbar === */}
      <nav className="navbar">
        <div className="navbar-brand">
          <Link to="/">TheFolio</Link>
        </div>
        <div className="navbar-links">
          <div className="dropdown">
            <button className="dropdown-toggle">Menu ▾</button>
            <div className="dropdown-menu">
              <Link to="/home">Home</Link>
              {!user && (
                <>
                  <Link to="/login">Login</Link>
                  <Link to="/register">Register</Link>
                </>
              )}
              {user && (
                <>
                  <Link to="/create-post">Write Post</Link>
                  <Link to="/profile">Profile</Link>
                  {user.role === "admin" && <Link to="/admin">Admin</Link>}
                  <button onClick={handleLogout} className="btn-logout">
                    Logout
                  </button>
                </>
              )}
            </div>
          </div>
        </div>
      </nav>

      {/* === HomePage content === */}
      <section className="hero">
        <div className="hero-text">
          <h1 style={{ textAlign: "center" }}>Welcome to My Portfolio</h1>
          <p style={{ textAlign: "center" }}>Exploring my passion for Coding</p>
        </div>
      </section>

      <main>
        <div className="preview-container">
          <div className="preview">
            <h2>About My Journey</h2>
            <p>Learn how I got started with Coding and what inspires me.</p>
            <a href="/about">Read More →</a>
          </div>

          <div className="preview">
            <h2>Connect & Resources</h2>
            <p>Find useful resources and ways to reach out.</p>
            <a href="/contact">Explore →</a>
          </div>

          <div className="preview">
            <h2>Join the Community</h2>
            <p>Sign up to stay updated and share your interest.</p>
            <a href="/register">Register →</a>
          </div>
        </div>

        <section className="highlights">
          <h2>Key Highlights</h2>
          <ul>
            <li>Highlight 1 about Coding</li>
            <li>Highlight 2 about W3Schools</li>
            <li>Highlight 3 about Stack Overflow</li>
            <li>Highlight 4 about FreeCodeCamp</li>
          </ul>
        </section>

        <div className="home-page">
          <h2>Latest Posts</h2>
          {posts.length === 0 ? (
            <p>No posts yet. Be the first to write one!</p>
          ) : (
            <div className="posts-grid">
              {posts.map((post) => (
                <div key={post._id} className="post-card">
                  {post.image && (
                    <img
                      src={`http://localhost:5000/uploads/${post.image}`}
                      alt={post.title}
                    />
                  )}
                  <h3>
                    <Link to={`/posts/${post._id}`}>{post.title}</Link>
                  </h3>
                  <p>{post.body.substring(0, 120)}...</p>
                  <small>
                    By {post.author?.name} ·{" "}
                    {new Date(post.createdAt).toLocaleDateString()}
                  </small>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>

      <button className="theme-toggle" onClick={toggleTheme}>
        {darkMode ? "☀️ Light Mode" : "🌙 Dark Mode"}
      </button>

      <footer>
        <p>Contact: email@example.com | Phone: (000) 000-0000</p>
        <p>© 2026 My Passion Portfolio</p>
      </footer>
    </div>
  );
};

export default Navbar;
